mapper.select:
/* SQL ID : CrsDAO.selectList 설 명 : 과정 목록 */ SELECT ROW_NUMBER() OVER(ORDER BY A.MOD_DTTM, A.CRSNM) AS LINE_NO , A.CRS_ID , A.CRS_CTGRCD , A.CRSNM , A.CRS_EXPLN
, A.CRS_OP_TYCD
, A.FNSH_PROC_TYCD -- , A.DPLM_ISSUYN , A.CRS_TYCD , A.EDU_QUOTA , A.QUOTA_LMTYN , A.USEYN , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM
, (SELECT COUNT(*) FROM TB_LMS_SBJCT B WHERE B.CRS_ID = A.CRS_ID AND B.SBJCT_ID = NVL(NULL, B.SBJCT_ID)) AS CRE_CRS_CNT FROM TB_LMS_CRS A WHERE 1 = 1 AND A.DELYN = 'N' AND A.USEYN = 'Y'
AND A.SBJCT_TYCD = #{crsTypeCd}
AND A.CRS_ID = #{crsCd}
ORDER BY A.MOD_DTTM DESC, A.CRSNM

/* SQL ID : CrsDAO.selectCrsList 설 명 : 과정 목록 */
SELECT ROW_NUMBER() OVER(ORDER BY A.MOD_DTTM, A.CRSNM) AS LINE_NO , COUNT(1) OVER() AS TOTAL_CNT , A.CRS_ID , A.CRS_CTGRCD , A.CRSNM , A.CRS_EXPLN , A.SBJCT_OP_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'LEARNING_TYPE' AND CD = A.SBJCT_OP_TYCD) AS CRS_OPER_TYPE_NM , A.ENRL_CERT_MTHD , A.FNSH_PROC_TYCD , A.FNSH_SCR , A.DPLM_ISSUYN , A.SBJCT_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'SBJCT_TYCD' AND CD = A.SBJCT_TYCD) AS CRS_TYPE_NM , A.EDU_QUOTA , A.QUOTA_LMTYN , A.USEYN , (SELECT CRS_CTGRNM FROM TB_LMS_CRS_CTGR WHERE CRS_CTGRCD = A.CRS_CTGRCD ) AS CRS_CTGRNM , (SELECT COUNT(*) FROM TB_LMS_SBJCT B WHERE B.CRS_ID = A.CRS_ID AND B.SBJCT_ID = IFNULL(#{crsYear}, B.SBJCT_ID)) AS CRE_CRS_CNT , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM FROM TB_LMS_CRS A WHERE 1 = 1 AND A.DELYN = 'N' AND A.SBJCT_TYCD IN
#{crsTypeCdes}
AND LOWER(A.CRSNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
ORDER BY LINE_NO DESC

mapper.update:
	/*
		 SQL ID : CrsDAO.updateUseYn
		 설  명 : 과정 목록 > 사용여부 변경
 	*/

	UPDATE TB_LMS_CRS
 	   SET USEYN  = #{useYn}
	     , MDFR_ID  = #{userId}
	     , MOD_DTTM  = FN_DTTM()
	 WHERE CRS_ID = #{crsCd}

mapper.select:
/* SQL ID : CrsDAO.selectCrsListExcelDown 설 명 : 과정 목록 엑셀 */ SELECT ROW_NUMBER() OVER(ORDER BY A.MOD_DTTM, A.CRSNM) AS LINE_NO , COUNT(1) OVER() AS TOTAL_CNT , A.CRS_ID , A.CRS_CTGRCD , A.CRSNM , A.CRS_EXPLN , A.SBJCT_OP_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'LEARNING_TYPE' AND CD = A.SBJCT_OP_TYCD) AS CRS_OPER_TYPE_NM , A.ENRL_CERT_MTHD , A.FNSH_PROC_TYCD , A.FNSH_SCR , A.DPLM_ISSUYN , A.SBJCT_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'SBJCT_TYCD' AND CD = A.SBJCT_TYCD) AS CRS_TYPE_NM , A.EDU_QUOTA , A.QUOTA_LMTYN , A.USEYN , (SELECT CRS_CTGRNM FROM TB_LMS_CRS_CTGR WHERE CRS_CTGRCD = A.CRS_CTGRCD ) AS CRS_CTGRNM , (SELECT COUNT(*) FROM TB_LMS_SBJCT B WHERE B.CRS_ID = A.CRS_ID AND B.SBJCT_ID = IFNULL(#{crsYear}, B.SBJCT_ID)) AS creCrsCnt FROM TB_LMS_CRS A WHERE 1 = 1 AND A.DELYN = 'N' AND A.SBJCT_TYCD IN
#{crsTypeCdes}
AND LOWER(A.CRSNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
ORDER BY LINE_NO DESC

