mapper.select:
/* SQL ID : CrsDAO.crsListPageing 설 명 : 과정 목록 */
SELECT ROW_NUMBER() OVER(ORDER BY MOD_DTTM, CRSNM) AS LINE_NO , R.* FROM (SELECT COUNT(1) OVER() AS TOTAL_CNT , TLC.CRS_ID , TLC.CRS_CTGRCD , TLC.CRSNM , TLC.CRS_EXPLN , TLC.SBJCT_OP_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'LEARNING_TYPE' AND CD = TLC.SBJCT_OP_TYCD) AS CRS_OPER_TYPE_NM , TLC.ENRL_CERT_MTHD , TLC.FNSH_PROC_TYCD , TLC.FNSH_SCR , TLC.DPLM_ISSUYN , TLC.SBJCT_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = TLC.ORG_ID AND CTGRCD = 'SBJCT_TYCD' AND CD = TLC.SBJCT_TYCD) AS CRS_TYPE_NM , TLC.EDU_QUOTA , TLC.QUOTA_LMTYN , TLC.USEYN , TLC.RGTR_ID , TLC.FRST_INQ_DTTM , TLC.MDFR_ID , TLC.MOD_DTTM , (SELECT CRS_CTGRNM FROM TB_LMS_CRS_CTGR WHERE CRS_CTGRCD = TLC.CRS_CTGRCD ) AS CRS_CTGRNM , (SELECT COUNT(*) FROM TB_LMS_SBJCT B WHERE B.CRS_ID = TLC.CRS_ID AND B.DELYN = 'N') AS CRE_CRS_CNT FROM TB_LMS_CRS TLC WHERE 1 = 1 AND TLC.DELYN = 'N'
AND TLC.CRS_ID = #{crsCd}
AND TLC.CRS_CTGRCD = #{crsCtgrCd}
AND TLC.SBJCT_OP_TYCD = #{crsOperTypeCd}
AND TLC.SBJCT_TYCD = #{crsTypeCd}
AND TLC.ORG_ID = #{orgId}
AND TLC.SBJCT_TYCD IN
#{item}
AND LOWER(TLC.CRSNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
ORDER BY TLC.CRSNM ) R ORDER BY LINE_NO DESC

/* SQL ID : CrsDAO.list 설 명 : 과정 목록 */ SELECT ROW_NUMBER() OVER(ORDER BY A.MOD_DTTM, A.CRSNM) AS LINE_NO , A.CRS_ID , A.CRS_CTGRCD , A.CRSNM , A.CRS_EXPLN -- , A.CRS_OP_TYCD
, A.FNSH_PROC_TYCD
, A.DPLM_ISSUYN , A.CRS_TYCD , A.EDU_QUOTA , A.QUOTA_LMTYN , A.USEYN , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM
, (SELECT COUNT(*) FROM TB_LMS_SBJCT B WHERE B.CRS_ID = A.CRS_ID AND B.SBJCT_ID = NVL(NULL, B.SBJCT_ID)) AS CRE_CRS_CNT FROM TB_LMS_CRS A WHERE 1 = 1 AND A.DELYN = 'N' AND A.USEYN = 'Y'
AND A.CRS_ID = #{crsCd}
AND A.ORG_ID = #{orgId}
AND LOWER(A.CRSNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
ORDER BY A.MOD_DTTM, A.CRSNM

