mapper.select:
/* SQL ID : CrsDAO.listCrsPreview 설 명 : 과목 미리보기 */ SELECT TLCICT.CRS_ID , TLCICT.CRS_CONTS_ID , TLCICT.CRS_CONTS_GBNCD , TLCICT.CONTS_SEQ , TLCICT.CONTS_FILE_POS_CD , TLCICT.CONTS_FILENM , TLCICT.CONTS_FILE_PATH , TLCICT.CONTS_URL , TLCICT.RGTR_ID , TLCICT.FRST_INQ_DTTM , CASE WHEN TLCICT.CRS_CONTS_GBNCD = 'CRS_INTRO' THEN 1 WHEN TLCICT.CRS_CONTS_GBNCD != 'CRS_INTRO' THEN 2 ELSE 2 END AS SORT_ORDER FROM TB_LMS_CRS TLC LEFT OUTER JOIN CRS_CONTS TLCICT ON TLC.CRS_ID = TLCICT.CRS_ID WHERE 1 = 1
AND TLC.CRS_ID = #{crsCd}
AND TLCICT.CONTS_FILE_POS_CD = #{cntsFileLocCd}
AND TLCICT.CRS_CONTS_ID = #{crsInfoCntsCd}
AND TLC.ORG_ID = #{orgId}
AND IFNULL(TLC.USEYN, 'Y') != 'N' ORDER BY SORT_ORDER, TLCICT.CONTS_SEQ

mapper.insert:
	/*
		SQL ID : CrsDAO.mergeCrsInfoCnts
		설  명 : 과목 미리보기 등록
 	*/
 	INSERT INTO CRS_CONTS (
	  	CRS_ID,
	  	CRS_CONTS_ID,
	  	CRS_CONTS_GBNCD,
	  	CONTS_SEQ,
	  	CONTS_FILE_POS_CD,
	  	CONTS_FILENM,
	  	CONTS_FILE_PATH,
	  	CONTS_URL,
	  	RGTR_ID,
	  	FRST_INQ_DTTM
	) VALUES (
	  	#{crsCd}
	  	, #{crsInfoCntsCd} 
	  	, #{crsInfoCntsDivCd}
	  	, #{cntsOrder}
	  	, #{cntsFileLocCd}
	  	, #{cntsFileNm}
	  	, #{cntsFilePath}
	  	, #{cntsUrl}
	  	, #{rgtrId}
	  	, FN_DTTM()
	)
	ON DUPLICATE KEY 
	 	UPDATE
		 CONTS_SEQ = #{cntsOrder} 
		 , CONTS_FILE_POS_CD = #{cntsFileLocCd}
	  	 , CONTS_FILENM = #{cntsFileNm}
	   	 , CONTS_FILE_PATH = #{cntsFilePath}
	  	 , CONTS_URL = #{cntsUrl}

mapper.delete:
	/*
		SQL ID : CrsDAO.deleteCrsInfoCnts
		설  명 : 과목 미리보기 삭제
 	*/
 	DELETE FROM CRS_CONTS 
	 WHERE CRS_ID = #{crsCd} 
	   AND CRS_CONTS_ID NOT IN 

 		 #{item}

mapper.select:
	/*
		 SQL ID : CrsDAO.selectNewCrsCd
		 설  명 : 외부기관의 과정번호 생성
 	*/
	SELECT IFNULL(CRS_ID, CONCAT(#{orgId}, 'CRS1')) CRS_ID 
	FROM (
		SELECT CONCAT(ORG_ID, 'CRS', COUNT(1) + 1) CRS_ID
		FROM TB_LMS_CRS 
		WHERE ORG_ID =  #{orgId}
	) X
